/**
 * @param {number} n
 * @param {number[][]} edges
 * @return {number}
 */
function solve(n, edges) {
    // DSU structure initialization
    const parent = Array(n).fill(0).map((_, i) => i);
    // diff[i] stores the parity of the path weight from i to parent[i]
    const diff = Array(n).fill(0);
    // size[i] stores the size of the component rooted at i
    const size = Array(n).fill(1);

    /**
     * Finds the root of node i and the parity distance from i to the root.
     * Uses path compression.
     * @param {number} i
     * @returns {{root: number, parity: number}}
     */
    function find(i) {
        if (parent[i] === i) {
            return { root: i, parity: 0 };
        }

        // Recursive call to find root and update parent[parent[i]]
        const { root, parity: rootParity } = find(parent[i]);

        // Update difference: D(i, root) = D(i, old_parent) XOR D(old_parent, root)
        diff[i] = diff[i] ^ rootParity;

        // Path compression
        parent[i] = root;

        return { root: root, parity: diff[i] };
    }

    let addedEdgesCount = 0;

    for (const [u, v, w] of edges) {
        // 1. Find representatives and parities
        const { root: ru, parity: du } = find(u);
        const { root: rv, parity: dv } = find(v);

        if (ru === rv) {
            // Case 1: Same component. Check for odd cycle creation.
            // Cycle weight = D(u, ru) XOR w XOR D(v, ru)
            const cycleWeight = du ^ w ^ dv;

            if (cycleWeight === 0) {
                // Cycle weight is even, acceptable
                addedEdgesCount++;
            }
            // If cycleWeight is 1, we reject the edge as it creates an odd cycle.
        } else {
            // Case 2: Different components. Merge them.

            // Union by size heuristic
            let new_ru, new_rv;
            if (size[ru] < size[rv]) {
                new_ru = ru;
                new_rv = rv;
                // Swap roles so we merge the smaller tree (ru) into the larger tree (rv)
                // The logic below assumes we merge ru into rv if size[ru] < size[rv]
            } else {
                new_ru = rv;
                new_rv = ru;
                // Swap roles for simpler implementation below
            }

            // Let's stick to standard merging: merge ru into rv if size[ru] < size[rv]
            if (size[ru] > size[rv]) {
                // Swap (u, v) roles internally to ensure ru is the smaller component root
                const temp = ru; ru = rv; rv = temp;
                const temp_d = du; du = dv; dv = temp_d;
            }

            // Now, ru is the root of the smaller or equal sized component. We merge ru into rv.

            // We set parent[ru] = rv. We need to calculate diff[ru] = Parity(ru -> rv).
            // We know:
            // 1. Parity(u -> ru) = du
            // 2. Parity(v -> rv) = dv
            // 3. Parity(u -> v) = w
            // Path: ru -> u --w--> v -> rv
            // Parity(ru -> rv) = Parity(ru -> u) XOR w XOR Parity(v -> rv)
            // Parity(ru -> u) = Parity(u -> ru) = du (since XOR is its own inverse)

            // Parity(ru -> rv) = du XOR w XOR dv
            diff[ru] = du ^ w ^ dv;

            parent[ru] = rv;
            size[rv] += size[ru];

            // Edge successfully added
            addedEdgesCount++;
        }
    }

    return addedEdgesCount;
}

