const Int64 = Int64

#struct DSUState {
    parent: Int,
    diff: Int, // Parity of path weight to parent
    size: Int,
}

#fn find(dsu: Kernel<DSUState>, i: Int) -> { root: Int, parity: Int } {
    if dsu.parent[i] == i {
        return { root: i, parity: 0 }
    }

    // Recursive call to find root and update parent[parent[i]]
    let res = find(dsu, dsu.parent[i])
    let root = res.root
    let rootParity = res.parity

    // Update difference: D(i, root) = D(i, old_parent) XOR D(old_parent, root)
    dsu.diff[i] = dsu.diff[i] ^ rootParity

    // Path compression
    dsu.parent[i] = root

    return { root: root, parity: dsu.diff[i] }
}

#fn solve(n: Int64, edges: Array(Array(Int64))) : Int64 {
    // Use Int for indices and component IDs since N <= 5*10^4
    let n_int = n.to_int

    // Initialize DSU structure
    let parent = Array(n_int) { |i| i }
    let diff = Array(n_int) { |i| 0 } // Parity distance to parent
    let size = Array(n_int) { |i| 1 }

    // We wrap these arrays into a structure to pass around the DSU state cleanly
    let dsu = Kernel<DSUState>{
        parent: parent,
        diff: diff,
        size: size
    }

    let mut addedEdgesCount: Int = 0

    for edge in edges {
        // u, v, w are Int64 from input, convert to Int for DSU operations
        let u = edge[0].to_int
        let v = edge[1].to_int
        let w = edge[2].to_int // w is 0 or 1

        // 1. Find representatives and parities
        let res_u = find(dsu, u)
        let ru = res_u.root
        let du = res_u.parity

        let res_v = find(dsu, v)
        let rv = res_v.root
        let dv = res_v.parity

        if ru == rv {
            // Case 1: Same component. Check for odd cycle creation.
            // Cycle weight = D(u, ru) XOR w XOR D(v, ru)
            let cycleWeight = du ^ w ^ dv

            if cycleWeight == 0 {
                // Cycle weight is even, acceptable
                addedEdgesCount += 1
            }
            // If cycleWeight is 1, we reject the edge as it creates an odd cycle.
        } else {
            // Case 2: Different components. Merge them (Union by Size).

            // Ensure ru is the root of the smaller or equal sized component.
            if dsu.size[ru] > dsu.size[rv] {
                // Swap roles internally: ru becomes rv's role, rv becomes ru's role
                let temp_ru = ru
                let temp_du = du

                ru = rv
                rv = temp_ru
                du = dv
                dv = temp_du
